import{_ as t,o,c as s,ag as a}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"V5.3 contracts release — rotationNewWallet 160-bit range-check (F2)","description":"","frontmatter":{},"headers":[],"relativePath":"release-notes/v0.5.3-contracts.md","filePath":"release-notes/v0.5.3-contracts.md","lastUpdated":1777921494000}'),r={name:"release-notes/v0.5.3-contracts.md"};function i(n,e,d,c,l,h){return o(),s("div",null,[...e[0]||(e[0]=[a(`<h1 id="v5-3-contracts-release-—-rotationnewwallet-160-bit-range-check-f2" tabindex="-1">V5.3 contracts release — <code>rotationNewWallet</code> 160-bit range-check (F2) <a class="header-anchor" href="#v5-3-contracts-release-—-rotationnewwallet-160-bit-range-check-f2" aria-label="Permalink to &quot;V5.3 contracts release — \`rotationNewWallet\` 160-bit range-check (F2)&quot;">​</a></h1><p><strong>Renamed in v0.6.0</strong> — content reflects v0.5.x state; subsequent versions use zkqes nomenclature.</p><p><strong>Package:</strong> <code>@qkb/contracts</code>, <code>@qkb/contracts-sdk</code>, <code>@qkb/sdk</code><strong>Version:</strong> <code>0.5.2-pre</code> → <code>0.5.3-pre</code><strong>Branch:</strong> <code>feat/v5_3-contracts</code> (commit <code>1b260d8</code>) <strong>Spec:</strong> <code>docs/superpowers/specs/2026-05-03-v5_3-oid-anchor-amendment.md</code> (founder-approved v0.1) <strong>Predecessor release:</strong> <code>docs/release-notes/v0.5.2-contracts.md</code> (V5.2 keccak-on-chain amendment, <code>v0.5.2-pre-ceremony</code>)</p><p>V5.3 is an <strong>in-place amendment to the V5.2 contract</strong> (NOT a new contract). The V5.2 amendment design picks up F2 (rotationNewWallet 160-bit range-check) on the contract side; F1 (subject-serial OID-anchor) and F3 (walletSecret↔msgSender doc) are circuits-eng&#39;s track. Public-signal layout is <strong>frozen at V5.2&#39;s 22 signals</strong> — this release does not touch ABI shape, selectors, storage layout, or downstream SDK fixtures.</p><h2 id="tl-dr-for-downstream-consumers" tabindex="-1">TL;DR for downstream consumers <a class="header-anchor" href="#tl-dr-for-downstream-consumers" aria-label="Permalink to &quot;TL;DR for downstream consumers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Consumer surface</th><th>Breaking change?</th><th>Action required</th></tr></thead><tbody><tr><td><code>IQKBRegistry</code> view ABI</td><td><strong>No</strong> — selectors byte-identical V5.2 → V5.3</td><td>None.</td></tr><tr><td><code>register(...)</code> / <code>rotateWallet(...)</code> write ABI</td><td><strong>No</strong> — function selectors unchanged (public-signal tuple shape unchanged)</td><td>None. SDK + integrators keep <code>qkbRegistryV5_2Abi</code> from <code>@qkb/sdk</code>.</td></tr><tr><td>Witness builder / circuit</td><td><strong>Yes</strong> — circuit gains F1 (private input <code>subjectSerialOidOffsetInTbs</code>) + F2 in-circuit <code>Num2Bits(160)</code> + F3 doc</td><td>Use <code>buildWitnessV5_3</code> from <code>@qkb/sdk</code> (web-eng T5). Public-output layout still 22 — no calldata change.</td></tr><tr><td>Constructor signature</td><td><strong>No</strong> — <code>(IGroth16VerifierV5_2, address, bytes32, bytes32)</code> unchanged</td><td>None.</td></tr><tr><td>Storage layout (off-chain indexers)</td><td><strong>No</strong> — slots 0..6 byte-identical V5.2 → V5.3</td><td>None.</td></tr><tr><td>Contract address on Sepolia / mainnet</td><td><strong>Yes for the verifier; no for the registry source</strong> — the registry source is <code>QKBRegistryV5_2.sol</code> (still); a fresh deploy is required because the registry&#39;s <code>groth16Verifier</code> is <code>immutable</code> and must point at the new V5.3 ceremonied verifier</td><td>Re-run <code>script/DeployV5_2.s.sol</code> with <code>GROTH16_VERIFIER_ADDR</code> set to the V5.3 ceremony output. Update <code>fixtures/contracts/sepolia.json</code> post-deploy.</td></tr><tr><td>Custom error selectors</td><td><strong>No</strong> — <code>InvalidNewWallet()</code> semantics generalize without selector change</td><td>None.</td></tr></tbody></table><h2 id="why-v5-3-contract-side" tabindex="-1">Why V5.3 (contract-side) <a class="header-anchor" href="#why-v5-3-contract-side" aria-label="Permalink to &quot;Why V5.3 (contract-side)&quot;">​</a></h2><p>V5.2&#39;s contract review surfaced three findings; F2 is the contract-side one. The V5.2 <code>rotateWallet()</code> flow contains a silent-truncation surface at the public-signal unpack:</p><div class="language-solidity vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">solidity</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">address</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> newWallet </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> address</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">uint160</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sig.rotationNewWallet));</span></span></code></pre></div><p><code>sig.rotationNewWallet</code> is a public-signal slot (<code>uint256</code>, BN254 field-element-shaped). Without a range-check, a malicious prover can submit <code>sig.rotationNewWallet = (high_bits &lt;&lt; 160) | uint160(prover_addr)</code> — the cast yields <code>prover_addr</code>, the downstream <code>newWallet != msg.sender</code> check passes (prover prank as <code>prover_addr</code>), and the proof&#39;s slot 17 carries an arbitrary 254-bit field element that the proof commits to but the contract never validates against the cast result.</p><p>This is a <strong>defense-in-depth gap</strong> rather than an immediate exploit (the attacker still needs to satisfy the Groth16 pairing equation against the published verifier, and the V5.3 in-circuit <code>Num2Bits(160)</code> constraint will close the same hole at the circuit layer once circuits-eng&#39;s track lands). But the load-bearing-on-each-other discipline (gate at both circuit and contract) means either layer can be refactored without re-introducing the truncation surface.</p><h2 id="contract-side-change-one-diff" tabindex="-1">Contract-side change (one diff) <a class="header-anchor" href="#contract-side-change-one-diff" aria-label="Permalink to &quot;Contract-side change (one diff)&quot;">​</a></h2><p>In <code>QKBRegistryV5_2.rotateWallet()</code>, between the existing <code>WrongMode</code> mode gate and the Groth16 verify call:</p><div class="language-solidity vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">solidity</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// V5.3 F2: rotationNewWallet 160-bit range check.</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (sig.rotationNewWallet </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> uint256</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">uint160</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sig.rotationNewWallet))) {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    revert</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> InvalidNewWallet</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Insertion is at the <strong>earliest fail-fast position</strong> so malformed proofs don&#39;t pay the ~400K Groth16 verifier cost. The check uses the existing <code>InvalidNewWallet()</code> error declaration from V5.2 — semantics generalize from V5.2&#39;s &quot;newWallet == 0 || == oldWallet || != msg.sender&quot; to &quot;+ bits 160..255 nonzero&quot; without selector change.</p><h2 id="what-about-register" tabindex="-1">What about <code>register()</code>? <a class="header-anchor" href="#what-about-register" aria-label="Permalink to &quot;What about \`register()\`?&quot;">​</a></h2><p><strong>Not added</strong> — and intentionally so. The V5.2 <code>register()</code> flow already enforces an equivalent bound via the existing <code>WrongRegisterModeNoOp</code> gate:</p><div class="language-solidity vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">solidity</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (sig.rotationNewWallet </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> uint256</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">uint160</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">msg.sender</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))) {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    revert</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> WrongRegisterModeNoOp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><code>uint256(uint160(msg.sender))</code> is bounded by <code>2^160 - 1</code> by construction (any uint160 cast produces a value ≤ uint160.max). For this gate to PASS, <code>sig.rotationNewWallet</code> MUST equal that value, hence MUST be &lt; 2^160. F2 in <code>register()</code> would be <strong>structurally redundant</strong> — the existing gate already enforces the 160-bit bound as a side effect of the equality check.</p><p>Adding F2 to <code>register()</code> for spec-uniformity over structural redundancy was considered and rejected:</p><ul><li>~60 gas extra on the high-volume register path (vs zero benefit; the gate would never fire / never catch anything)</li><li>Future readers see two &quot;same&quot; gates and assume something subtle is going on</li><li>If <code>WrongRegisterModeNoOp</code> is ever refactored away, the resulting bug (&quot;register-mode rotateNewWallet unbounded&quot;) would be in plain sight + caught by its own test coverage anyway, NOT silenced by a second gate</li></ul><p>The contract-side F2 scope is therefore <strong>rotateWallet-only</strong>. Spec §F2.2&#39;s &quot;add to both flows&quot; guidance is being amended to reflect this in the v0.2 spec refresh.</p><h2 id="abi-changes" tabindex="-1">ABI changes <a class="header-anchor" href="#abi-changes" aria-label="Permalink to &quot;ABI changes&quot;">​</a></h2><h3 id="function-selectors" tabindex="-1">Function selectors <a class="header-anchor" href="#function-selectors" aria-label="Permalink to &quot;Function selectors&quot;">​</a></h3><p><strong>No changes.</strong> Verified via <code>forge inspect QKBRegistryV5_2 methodIdentifiers</code> against the V5.2 baseline. Same 15 selectors, byte-identical:</p><table tabindex="0"><thead><tr><th>Function</th><th>V5.2 → V5.3 selector</th></tr></thead><tbody><tr><td><code>register(...)</code></td><td><code>0x9ab660c7</code> (unchanged)</td></tr><tr><td><code>rotateWallet(...)</code></td><td><code>0x9849ff37</code> (unchanged)</td></tr><tr><td><code>isVerified(address)</code></td><td><code>0xb9209e33</code> (unchanged)</td></tr><tr><td><code>nullifierOf(address)</code></td><td><code>0x61e0a22e</code> (unchanged)</td></tr><tr><td>... all other view / admin / getter selectors</td><td>byte-identical</td></tr></tbody></table><p><strong>Implication:</strong> all SDK consumers (read or write) continue to use <code>qkbRegistryV5_2Abi</code>. No re-bind required.</p><h3 id="public-signal-layout" tabindex="-1">Public-signal layout <a class="header-anchor" href="#public-signal-layout" aria-label="Permalink to &quot;Public-signal layout&quot;">​</a></h3><p><strong>No changes.</strong> V5.3 keeps the V5.2 frozen layout exactly (22 signals, slots 0..21). F2&#39;s contract-side check operates on slot 17 (<code>rotationNewWallet</code>) without altering its position or shape. F1 + F3 (circuits-eng&#39;s track) add private witness inputs but no new public outputs.</p><h3 id="custom-errors" tabindex="-1">Custom errors <a class="header-anchor" href="#custom-errors" aria-label="Permalink to &quot;Custom errors&quot;">​</a></h3><p><strong>No new selectors.</strong> F2 reuses the existing <code>InvalidNewWallet()</code> (<code>0xbdf7f17f</code>) declared in V5.2:</p><table tabindex="0"><thead><tr><th>Error</th><th>V5.2 selector</th><th>V5.3 selector</th><th>Notes</th></tr></thead><tbody><tr><td><code>InvalidNewWallet()</code></td><td><code>0xbdf7f17f</code></td><td><code>0xbdf7f17f</code></td><td><strong>Semantics generalized</strong> from &quot;newWallet == 0 || == oldWallet || != msg.sender&quot; to &quot;+ bits 160..255 nonzero&quot;. Selector unchanged ⇒ revert classifiers do not need updating.</td></tr></tbody></table><p>All other 28 error selectors byte-identical V5.2 → V5.3.</p><h2 id="storage-layout" tabindex="-1">Storage layout <a class="header-anchor" href="#storage-layout" aria-label="Permalink to &quot;Storage layout&quot;">​</a></h2><p><strong>Identical V5.2 → V5.3</strong> — verified via <code>forge inspect QKBRegistryV5_2 storageLayout</code> diff. F2 adds no new state variables; the gate is calldata-driven + revert-only. Same 7 slots V5/V5.1/V5.2/V5.3:</p><table tabindex="0"><thead><tr><th>Slot</th><th>Name</th><th>Type</th></tr></thead><tbody><tr><td>0</td><td><code>admin</code></td><td><code>address</code></td></tr><tr><td>1</td><td><code>trustedListRoot</code></td><td><code>bytes32</code></td></tr><tr><td>2</td><td><code>policyRoot</code></td><td><code>bytes32</code></td></tr><tr><td>3</td><td><code>nullifierOf</code></td><td><code>mapping(address =&gt; bytes32)</code></td></tr><tr><td>4</td><td><code>identityCommitments</code></td><td><code>mapping(bytes32 =&gt; bytes32)</code></td></tr><tr><td>5</td><td><code>identityWallets</code></td><td><code>mapping(bytes32 =&gt; address)</code></td></tr><tr><td>6</td><td><code>usedCtx</code></td><td><code>mapping(bytes32 =&gt; mapping(bytes32 =&gt; bool))</code></td></tr></tbody></table><h2 id="constructor-signature" tabindex="-1">Constructor signature <a class="header-anchor" href="#constructor-signature" aria-label="Permalink to &quot;Constructor signature&quot;">​</a></h2><p><strong>No changes.</strong> <code>QKBRegistryV5_2.constructor(IGroth16VerifierV5_2, address, bytes32, bytes32)</code> is byte-identical V5.2 → V5.3. <code>script/DeployV5_2.s.sol</code> is reusable for the V5.3 deploy with no edits — only the <code>GROTH16_VERIFIER_ADDR</code> env value changes (point at the V5.3 ceremonied verifier instead of the V5.2 one).</p><h2 id="gas-measurements" tabindex="-1">Gas measurements <a class="header-anchor" href="#gas-measurements" aria-label="Permalink to &quot;Gas measurements&quot;">​</a></h2><p>Per-call F2 cost on <code>rotateWallet()</code> (when fired), measured via <code>forge snapshot</code> diff of <code>packages/contracts/snapshots/gas-snapshot.txt</code>:</p><table tabindex="0"><thead><tr><th>Test path (rotateWallet)</th><th>V5.2 gas</th><th>V5.3 gas</th><th>Δ</th></tr></thead><tbody><tr><td><code>test_rotateWallet_v52_revertsCommitmentMismatch</code></td><td>1,813,858</td><td>1,813,922</td><td>+64</td></tr><tr><td><code>test_rotateWallet_v52_revertsInvalidNewWallet_whenSenderNotNewWallet</code></td><td>1,814,352</td><td>1,814,416</td><td>+64</td></tr><tr><td><code>test_rotateWallet_v52_revertsInvalidRotationAuth_whenSigByWrongKey</code></td><td>1,820,788</td><td>1,820,852</td><td>+64</td></tr><tr><td><code>test_rotateWallet_v52_revertsUnknownIdentity_whenFingerprintNotClaimed</code></td><td>31,676</td><td>31,740</td><td>+64</td></tr><tr><td><code>test_rotateWallet_v52_revertsWrongMode_whenMode0</code></td><td>1,808,980</td><td>1,808,984</td><td>+4 (jumptable noise)</td></tr></tbody></table><p><strong>True F2 per-call cost: ~60 gas</strong> (rotateWallet paths that reach F2 see a uniform +64 gas; the WrongMode path which reverts BEFORE F2 sees only +4 gas, indicating the +60 is genuinely the F2 gate firing; the +4 elsewhere is bytecode-position-shift compiler noise).</p><p>Other small gas deltas across non-rotate tests (~14-100 gas across constructor, register, admin, setter paths) are bytecode-position shifts from adding ~400 bytes of new revert path. <strong>Compiler noise — not real per-call cost.</strong> <code>RealTupleGasSnapshotV5_2</code> register-path measurements unchanged (F2 gate not on the register code path).</p><p>V5 spec §3 acceptance gate (revised at commit <code>def6270</code> from 600K → 2.5M) still holds with comfortable margin.</p><h2 id="what-stayed-the-same" tabindex="-1">What stayed the same <a class="header-anchor" href="#what-stayed-the-same" aria-label="Permalink to &quot;What stayed the same&quot;">​</a></h2><ul><li><strong><code>IQKBRegistry</code> interface</strong> — selectors and return types byte-identical V5/V5.1/V5.2/V5.3.</li><li><strong>Storage layout</strong> — 7 slots, byte-identical to V5.2.</li><li><strong>Constructor signature</strong> — <code>(verifier, admin, trustRoot, policyRoot)</code> parity-equivalent.</li><li><strong><code>register()</code> flow</strong> — F2 not added (structurally redundant per §&quot;What about register()?&quot;); V5.2 register-path gas measurements unchanged.</li><li><strong>Public-signal layout</strong> — 22 signals, frozen per V5.2 §&quot;Public-signal layout&quot;.</li><li><strong>All non-<code>InvalidNewWallet</code> custom error selectors</strong> — byte-identical.</li><li><strong><code>rotateWallet()</code> rotation auth model</strong> — ECDSA sig from <code>oldWallet</code>&#39;s privkey over the rotation payload (chainid + registry addr + fingerprint + newWallet); F2 fires before the auth check.</li><li><strong><code>script/DeployV5_2.s.sol</code></strong> — reusable for V5.3 deploy with same env layout; only <code>GROTH16_VERIFIER_ADDR</code> changes.</li><li><strong>First-claim nullifier semantics</strong> — V5.1 invariant 4 (<code>nullifierOf</code> write-once on first-claim, migrates atomically on <code>rotateWallet</code>) preserved verbatim.</li></ul><h2 id="migration-guidance" tabindex="-1">Migration guidance <a class="header-anchor" href="#migration-guidance" aria-label="Permalink to &quot;Migration guidance&quot;">​</a></h2><h3 id="for-sdk-consumers-web-integrators" tabindex="-1">For SDK consumers (web, integrators) <a class="header-anchor" href="#for-sdk-consumers-web-integrators" aria-label="Permalink to &quot;For SDK consumers (web, integrators)&quot;">​</a></h3><ol><li>Bump dependency: <code>@qkb/sdk@0.5.3-pre</code>.</li><li><strong>No ABI re-bind needed.</strong> All selectors byte-identical V5.2 → V5.3. Continue using <code>qkbRegistryV5_2Abi</code>.</li><li><strong>No revert-classifier change.</strong> <code>InvalidNewWallet</code>&#39;s selector is preserved; the new high-bits-set trigger condition reverts with the same selector existing classifiers already handle.</li><li><strong>For witness builders</strong>: pick up V5.3 witness-builder additions (F1&#39;s <code>subjectSerialOidOffsetInTbs</code> private input) when web-eng T5 lands. Public-output layout still 22 — no calldata change.</li></ol><h3 id="for-deployer-tooling" tabindex="-1">For deployer-tooling <a class="header-anchor" href="#for-deployer-tooling" aria-label="Permalink to &quot;For deployer-tooling&quot;">​</a></h3><ol><li>Use <code>script/DeployV5_2.s.sol</code> (unchanged) for the V5.3 deploy.</li><li>Point <code>GROTH16_VERIFIER_ADDR</code> at the V5.3 ceremonied verifier (post-Phase-B V5.3 multi-contributor ceremony at <code>ceremony/v5_3/</code>).</li><li>Same env layout otherwise: <code>PRIVATE_KEY</code>, <code>ADMIN_ADDRESS</code>, <code>INITIAL_TRUST_ROOT</code>, <code>INITIAL_POLICY_ROOT</code>, <code>MINT_DEADLINE</code>, optional <code>CHAIN_LABEL</code>.</li></ol><h3 id="for-holders" tabindex="-1">For holders <a class="header-anchor" href="#for-holders" aria-label="Permalink to &quot;For holders&quot;">​</a></h3><p>V5.2 → V5.3 is a <strong>fresh deploy</strong>, not an upgrade. The registry contract itself (<code>QKBRegistryV5_2.sol</code>) is non-upgradeable; the F2 gate is in-place source amendment; the bytecode that rolls is the new bytecode of the V5.3 deploy + a new V5.3-ceremonied <code>groth16Verifier</code> immutable. Existing V5.2 holders re-register against the new V5.3 registry via the standard fresh-QES flow.</p><p>The two registries (V5.2 and V5.3) can coexist on-chain during the transition window; downstream consumers point at one or the other via deployment-fixture configuration (<code>fixtures/contracts/{sepolia,mainnet}.json</code>).</p><h2 id="acceptance" tabindex="-1">Acceptance <a class="header-anchor" href="#acceptance" aria-label="Permalink to &quot;Acceptance&quot;">​</a></h2><ul><li><code>forge build</code>: clean (<code>via_ir</code>, <code>optimizer_runs=200</code>).</li><li><code>forge test</code>: <strong>412 passed / 0 failed / 1 skipped / 413 total</strong> (was 410 in V5.2 baseline; +2 V5.3 F2 tests — <code>test_rotateWallet_v53_revertsInvalidNewWallet_whenRotationNewWalletExceeds160Bits</code> + <code>test_rotateWallet_v53_succeeds_atUint160Boundary_2pow160Minus1</code>; 1 env-gated skip = <code>test_deploy_base_sepolia_fork</code>).</li><li><code>forge snapshot</code>: refreshed at <code>packages/contracts/snapshots/gas-snapshot.txt</code> (commit <code>1b260d8</code>).</li><li>Cross-package integrity: SDK ABI surface unchanged (no re-pump needed); <code>pnpm -F @qkb/sdk test</code> continues to pass against <code>qkbRegistryV5_2Abi</code> from V5.2 baseline.</li></ul><h2 id="outstanding-before-mainnet" tabindex="-1">Outstanding before mainnet <a class="header-anchor" href="#outstanding-before-mainnet" aria-label="Permalink to &quot;Outstanding before mainnet&quot;">​</a></h2><ul><li><strong>V5.3 multi-contributor Phase-B ceremony</strong> — produces the V5.3 <code>groth16Verifier</code> (the V5.3 circuit&#39;s <code>Num2Bits(160)</code> constraint changes the R1CS, requiring a new Phase-2 ceremony; pot22 is reusable, no need for pot23).</li><li><strong>V5.3 stub ceremony script</strong> — circuits-eng T3 produces <code>Groth16VerifierV5_3Stub.sol</code> for real-pairing gas measurement against the V5.3 vkey.</li><li><strong>V5.3 RealTupleGasSnapshot integration test</strong> — sibling to <code>RealTupleGasSnapshotV5_2.t.sol</code> against the V5.3 stub. Will gain a rotate-path fixture so the V5.3 happy-path can be tested as a true round-trip (the V5.3 unit-suite F2 boundary test uses a downstream-revert surrogate because the V5.2 unit fixture&#39;s <code>holder</code> address is keccak-derived without a known privkey).</li><li><strong>Sepolia E2E gate</strong> (orchestration §9.4) — full register flow against real V5.3 ceremonied verifier on Base Sepolia.</li><li><strong>web-eng T5 completion</strong> — V5.3 witness builder (F1 private input + F2/F3 no-op) + SDK fixtures.</li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>V5.2 contracts release: <code>docs/release-notes/v0.5.2-contracts.md</code></li><li><strong>V5.3 amendment design (founder-approved v0.1):</strong> <code>docs/superpowers/specs/2026-05-03-v5_3-oid-anchor-amendment.md</code></li><li>V5.3 orchestration plan: <code>docs/superpowers/plans/2026-05-03-v5_3-orchestration.md</code></li><li>V5.2 amendment spec: <code>docs/superpowers/specs/2026-05-01-keccak-on-chain-amendment.md</code></li><li>V5.2 contract-side review (PASS-WITH-NOTES): <code>docs/superpowers/specs/2026-05-01-keccak-on-chain-contract-review.md</code></li><li>Gas-acceptance revision (600K → 2.5M): commit <code>def6270</code></li></ul>`,60)])])}const p=t(r,[["render",i]]);export{u as __pageData,p as default};
